#include <stdio.h>
#include <inttypes.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t X, Y, Z;
        scanf("%" PRId64 " %" PRId64 " %" PRId64, &X, &Y, &Z);
        int64_t sum = X + Y;
        if (sum < Z) {
            printf("PLANEBUS\n");
        } else if (sum > Z) {
            printf("TRAIN\n");
        } else {
            printf("EQUAL\n");
        }
    }
    return 0;
}

