#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        X = int(next(it)); Y = int(next(it)); Z = int(next(it))
        s = X + Y
        if s < Z:
            out_lines.append("PLANEBUS")
        elif s > Z:
            out_lines.append("TRAIN")
        else:
            out_lines.append("EQUAL")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

